datosAnalizarNum &lt;- dades[, intersect(variablesPasanFase1, varNum), drop = FALSE]

if (ncol(datosAnalizarNum) &gt; 0) {
  psych::describeBy(datosAnalizarNum, dades$cluster, mat = TRUE)
